import{_ as s,o as i,c as e,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"75. Classifications","description":"","frontmatter":{"title":"75. Classifications","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/classification-staffing/75-classifications.md","filePath":"ebas/has-managers-admin/common-terms/classification-staffing/75-classifications.md"}'),n={name:"ebas/has-managers-admin/common-terms/classification-staffing/75-classifications.md"};function o(c,a,l,r,m,f){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="_75-classifications" tabindex="-1">75. Classifications <a class="header-anchor" href="#_75-classifications" aria-label="Permalink to &quot;75. Classifications&quot;">​</a></h1><p><strong>75.1</strong> The Employer will classify all Employees in accordance with the classification structure set out in <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a> or <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> (as applicable).</p><p><strong>75.2</strong> The Employer will notify each Employee in writing upon commencement, of their classification and terms of employment.</p><p><strong>75.3</strong> The Employer will notify each Employee of any alteration to their classification in writing not later than the operative date of such change.</p><p>Plain language terms: grade, level, classification structure.</p>',5)])])}const p=s(n,[["render",o]]);export{d as __pageData,p as default};
